def main():
    buildings = [(0, 0), (5, 0), (0, 6), (4, 1), (0, 0)]
    # Check bounds and uniqueness
    seen = set()
    for x, y in buildings:
        if not (0 <= x <= 7 and 0 <= y <= 7):
            print("INVALID")
            return
        if (x, y) in seen:
            print("INVALID")
            return
        seen.add((x, y))
    print("VALID")

if __name__ == "__main__":
    main()

def has_water_access(nest, pond=(2, 0), max_dist=3):
    return abs(nest[0] - pond[0]) + abs(nest[1] - pond[1]) <= max_dist

nests = [(4, 0), (4, 3), (2, 5)]
if all(has_water_access(n) for n in nests):
    print("SAFE")
else:
    print("UNSAFE")

