nests = [(1,4), (2,0)]
fences = [(1,2), (2,3)]

def is_guarded(nest):
    x_n, y_n = nest
    for fx, fy in fences:
        if abs(x_n - fx) + abs(y_n - fy) <= 3:
            return True
    return False

if all(is_guarded(n) for n in nests):
    print("SAFE")
