#!/usr/bin/env python3
import sys

def main():
    secret = None
    try:
        with open('data.txt', 'r') as f:
            for line in f:
                if line.startswith('SECRET='):
                    secret = line.strip().split('=', 1)[1]
                    break
    except FileNotFoundError:
        print("data.txt not found", file=sys.stderr)
        sys.exit(1)

    if secret is None:
        print("No SECRET line found", file=sys.stderr)
        sys.exit(1)

    with open('answer.txt', 'w') as out:
        out.write(secret + '\\n')

if __name__ == "__main__":
    main()
